#!/usr/bin/env python3
"""
Bug #2304: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['constant', 'self_sub_zero'], ['branch', 'rrelu_inference_identity'], ['branch', 'glu'], ['constant', 'concat_single_input'], ['broadcast', 'cumsum_last_axis'], ['fusion', 'matmul_bias_gelu']]
Dependencies: numpy jax
Run         : python unique_2304.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("3333333e"), dtype=np.float32).reshape([1])
_w1 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w2 = np.frombuffer(bytes.fromhex("20000000000000002000000000000000"), dtype=np.int64).reshape([2])
_w3 = np.frombuffer(bytes.fromhex("0100000000000000"), dtype=np.int64).reshape([1])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([32, 64])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([64])
_w6 = np.frombuffer(bytes.fromhex("f304b53f"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex("0000003f"), dtype=np.float32).reshape([1])
_w8 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 64])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_ssz_sub = x - x
    n0_ssz_out = n0_ssz_sub + x
    n100_rrid_scl = n0_ssz_out * _w0
    n100_rrid_gt = (n0_ssz_out > _w1)
    n100_rrid_out = jnp.where(n100_rrid_gt, n0_ssz_out, n100_rrid_scl)
    _split_5 = jnp.split(n100_rrid_out, [32], axis=-1)
    n200_glu_a = _split_5[0]
    n200_glu_b = _split_5[1]
    n200_glu_sig = (np.float32(1.0) / (np.float32(1.0) + jnp.exp(-n200_glu_b)))
    n200_glu_out = n200_glu_a * n200_glu_sig
    n300_csi_cat = jnp.concatenate([n200_glu_out], axis=0)
    n300_csi_out = n300_csi_cat * n200_glu_out
    n400_cs_out = jnp.cumsum(n300_csi_out, axis=int(_w3.flat[0]))
    n500_mmbgelu_mm = jnp.matmul(n400_cs_out, _w4)
    n500_mmbgelu_add = n500_mmbgelu_mm + _w5
    n500_mmbgelu_div = n500_mmbgelu_add / _w6
    n500_mmbgelu_erf = jax.scipy.special.erf(n500_mmbgelu_div)
    n500_mmbgelu_erf1 = n500_mmbgelu_erf + _w8
    n500_mmbgelu_mul1 = n500_mmbgelu_add * _w7
    n500_mmbgelu_out = n500_mmbgelu_mul1 * n500_mmbgelu_erf1
    return jnp.asarray(n500_mmbgelu_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
